+
+  // Boundary Condition (Positive Ratio larger than 1.0)
+  {
+    geometry_msgs::msg::Pose src_pose;
+    src_pose.position = create_point(0.0, 0.0, 0.0);
+    src_pose.orientation = create_quaternion_from_rpy(deg2rad(0), deg2rad(0), deg2rad(0));
