+
+  {  // Both segments are the points which are different position
+    const auto p1 = create_point(0.0, 1.0, 0.0);
+    const auto p2 = create_point(0.0, 1.0, 0.0);
+    const auto p3 = create_point(1.0, 0.0, 0.0);
