+
+    const auto triangles = triangulate(poly);
+
+    const auto triangle_area = calculate_total_polygon_area(triangles);
+    const auto poly_area = boost::geometry::area(poly);
+    EXPECT_NEAR(triangle_area, poly_area, epsilon);
