+}
+
+std::optional<ConvexPolygon2d> ConvexPolygon2d::create(
+  const autoware_utils::Polygon2d & polygon) noexcept
+{
+  PointList2d vertices;
+  for (const auto & point : polygon.outer()) {
+    vertices.push_back(Point2d(point));
